sql:
SELECT subcategory_id, subcategory_name, category_id
FROM subcategories
WHERE description LIKE '%food trucks%';

SELECT COUNT(DISTINCT p.project_id) AS num_of_projects_with_comments
FROM projects p
INNER JOIN comments c ON p.project_id = c.project_id;

external_knowledge:
- "active navigators" refers to active users;
- "shelter in projects under the first star in the sky" refers to backing projects of subcategory_id = 1;
- "caught the eye of the celestial guides" refers to being a staff pick;
- "bathed in the spotlight of the night sky" refers to being featured in the spotlight.

sql:
SELECT p.project_id, p.company_name, p.blurb, p.goal, p.pledged, p.category_id, p.country, p.currency, p.deadline, p.staff_pick, p.spotlight, p.creator_id, p.last_updated_at, p.image_url, p.video_url, p.funding_type
FROM projects p
INNER JOIN staff_picks sp ON p.project_id = sp.project_id;

external_knowledge:
- "rivers of creativity" refers to the category names of projects;
- "most fertile ground" represents projects that are staff picks;
- "gardener with the greenest thumb" signifies the user who has selected the most projects as staff picks;
- "garden of project selections" is metaphorical, referring to the collection of projects and their staff picks.
